def modified_encode(input):
    if isinstance(input, str):
        groups = []
        prev_char = None
        count = 0
        for char in input:
            if char == prev_char:
                count += 1
            else:
                if prev_char is not None:
                    groups.append([count, prev_char])
                prev_char = char
                count = 1
        if prev_char is not None:
            groups.append([count, prev_char])
        result = []
        for group in groups:
            if group[0] == 1:
                result.append(group[1])
            else:
                result.append([group[0], group[1]])
        return result
    else:
        groups = []
        prev = None
        count = 0
        for item in input:
            if item == prev:
                count += 1
            else:
                if prev is not None:
                    groups.append([count, prev])
                prev = item
                count = 1
        if prev is not None:
            groups.append([count, prev])
        result = []
        for group in groups:
            if group[0] == 1:
                result.append(group[1])
            else:
                result.append([group[0], group[1]])
        return result

